public str getError()
{
    SysInfologEnumerator    sysInfologEnumerator;
    SysInfologMessageStruct infoMessageStruct;
    str                     logMessage;
    str                           logString;
    str                          ret;
    int                          i;
    #Define.NewLine('\n')
    sysInfologEnumerator = SysInfologEnumerator::newData(infolog.infologData());
    while (sysInfologEnumerator.moveNext())
    {
        i = 1;
        if (logMessage)
        {
            logMessage += #Newline;
        }
        infoMessageStruct = SysInfologMessageStruct::construct(sysInfologEnumerator.currentMessage());

        while (i <= infoMessageStruct.prefixDepth())
        {
            logString = logString + infoMessageStruct.preFixTextElement(i) + '. ';
            i++;
        }

        logString = logString + infoMessageStruct.message();
        logMessage = logMessage + infoMessageStruct.message();
    }

    infolog().clear();

    return logMessage;
}

public void createHeader()
{
    SalesAgreementHeaderEntity    salesAgreementHeader;

    CustTable                               custTable;
    DirPartyBaseEntity                      custTableDirParty;
    DictEnum                                dictEnumCommitmentType = new DictEnum(enumNum(CommitmentType));


    custTable                         = CustTable::find(custAccountLoc);
    if(salesNumberSequenceLoc)
    {
        salesAgreementHeader.SalesAgreementId = salesNumberSequenceLoc;
    }
    else
    {
        salesAgreementHeader.SalesAgreementId = NumberSeq::newGetNum(SalesParameters::numRefSalesAgreementId(),false).num();
    }

    salesAgreementHeader.CustAccount                    = custAccountLoc;
    salesAgreementHeader.AgreementCustomerAccountNumber = custAccountLoc;
    salesAgreementHeader.InvoiceCustomerAccountNumber   = invoiceAccount;
    salesAgreementHeader.BuyerDeliveryAddress           = custTable.postalAddress().RecId;
    salesAgreementHeader.SellerDeliveryAddress          = sellerDelAddressRecId;
    if(EffectiveDateLoc)
    {
    salesAgreementHeader.DefaultEffectiveDate           = EffectiveDateLoc;
    }
    else
    {
        salesAgreementHeader.DefaultEffectiveDate        = today();
    }
    salesAgreementHeader.AgreementType                  =  agreementType;
    salesAgreementHeader.SalesAgreementClassificationName = agreementClassificationLoc;
    salesAgreementHeader.ContactPersonId                  = contactPerson;
    salesAgreementHeader.ExternalReference                = externalReference;
    salesAgreementHeader.CustomerRequisitionNumber        = customerRequisitionNumber;
    salesAgreementHeader.CurrencyCode = currency;
    salesAgreementHeader.DocumentTitle = documentTitle;
    salesAgreementHeader.ExternalDocumentReference = documentExternalReference;
    salesAgreementHeader.BuyerAccountNum = buyerAccount;
    salesAgreementHeader.SellerAccountNum = sellerAccount;
    salesAgreementHeader.BuyerDeliveryAddress = custTable.postalAddress().RecId;
    salesAgreementHeader.SellerDeliveryAddress = CompanyInfo::find().postalAddress().RecId;


    salesAgreementHeader.ETG_PurchAgreementIdTP = etgPurchAgreementIdTP;
    salesAgreementHeader.ETG_PurchAgreementIdIC = etgPurchAgreementIdIC;
    salesAgreementHeader.TermPaymDescription = termPaymDescription;
    salesAgreementHeader.BuyerBank = buyerBank;
    salesAgreementHeader.SellerBank = sellerBank;
    salesAgreementHeader.PackingGroup = packingGroup;
    salesAgreementHeader.Notes = notes;
    salesAgreementHeader.ShipperBuyer = shipperBuyer;
    salesAgreementHeader.Consignee = consignee;
    salesAgreementHeader.OnAccountOf = onAccountOf;
    salesAgreementHeader.DeliveryDescription = deliveryDescription;
    salesAgreementHeader.Name = notifyName;
    salesAgreementHeader.Address = notifyAddress;
    salesAgreementHeader.TermsOfDelDescription = termsOfDelDescription;
    salesAgreementHeader.QuantityConditions = quantityConditions;


    salesAgreementHeader.PortOfLoading = portOfLoading;
    if(portOfLoading)
    {
        select firstonly Description from placeOfLoading where placeOfLoading.PlaceOfLoading == PortOFLoading;
        salesAgreementHeader.PortOfLoadingDesc   = placeOfLoading.Description;
    }
    else
    {
        salesAgreementHeader.PortOfLoadingDesc   = portOfLoadingDescNew;
    }

    salesAgreementHeader.PortOfDischarge = portOfDischarge;
    if(portOfDischarge)
    {
        select firstonly Description from placeOfDischarge where placeOfDischarge.PlaceOfDischarge == PortOfDischarge;
        salesAgreementHeader.PortOfDischargeDesc = placeOfDischarge.Description;
    }
    else
    {
        salesAgreementHeader.PortOfDischargeDesc = portOfDiscahargeNew;
    }

    salesAgreementHeader.CustomImport = customImport;
    salesAgreementHeader.PermitNumber = permitNumber;
    salesAgreementHeader.Fixation = fixation;
    salesAgreementHeader.Suppliercode = supplierCode;
    salesAgreementHeader.whLocationAndReceipt = whLocationAndReceipt;
    salesAgreementHeader.Drawnunderletterofcreditnumber = drawnUnderLetterOfCreditNumber;
    salesAgreementHeader.SHIPPEREXPORTER = shipperExporter;
    salesAgreementHeader.VESSELNAMEVOYAGE = vesselNameVoyage;
    salesAgreementHeader.VESSELSAILED = vesselSailed;
    salesAgreementHeader.GOODSDESCRIPTION2 = goodsDescription2;
    salesAgreementHeader.HSCODE = hsCode;
    salesAgreementHeader.SPECIALINSTRUCTIONS = specialInstructions;
    salesAgreementHeader.MARKS = marks;
    salesAgreementHeader.Notifyparty2 = notifyParty2;
    salesAgreementHeader.DIRECTCOURIERTOINDVTM = directCourierToIndvTM;
    salesAgreementHeader.SHIPPEDQUALITYDETAILSCERTIFICATE = shippedQualityDetailsCertificate;
    salesAgreementHeader.PaymentTerms = paymentTerms;
    salesAgreementHeader.CustomerMethodOfPayment = customerMethodOfPayment;
    salesAgreementHeader.CustomerPaymentSpec = customerPaymentSpec;
  //  salesAgreementHeader.PaymentSchedule = paymentScheduleSales;
    salesAgreementHeader.CashDiscountCode = cashDiscountCode;
    salesAgreementHeader.MiscChargeGroup = miscChargeGroup;
    salesAgreementHeader.Campaign = campaign;
    salesAgreementHeader.DeliveryModeCode = deliveryMode;
    salesAgreementHeader.DeliveryTermsCode = deliveryTerm;
    if(workerSalesResponsible)
    {
        salesAgreementHeader.WorkerSalesResponsible = HcmWorker::findByPerson(DirPerson::findByNum(DirPartyTable::findByName(workerSalesResponsible).PartyNumber).RecId).RecId;
    }
    salesAgreementHeader.SalesUnit = salesUnit;
    salesAgreementHeader.SalesPool = salesPool;
    salesAgreementHeader.CommissionSalesGroup = commissionSalesGroup;
    salesAgreementHeader.CommissionCustomerGroup = commissionCustomerGroup;

    if(future == "Yes")
    {
        salesAgreementHeader.Future = NoYes::Yes;
    }
    else
    {
        salesAgreementHeader.Future = NoYes::No;
    }
    if(notifyToDifferentParty == "Yes")
    {
        salesAgreementHeader.Notifytodifferentparty = NoYes::Yes;
    }
    else
    {
        salesAgreementHeader.Notifytodifferentparty = NoYes::No;
    }
    if(pdsExcludeFromRebate == "Yes")
    {
        salesAgreementHeader.PdsExcludeFromRebate = NoYes::Yes;
    }
    else
    {
        salesAgreementHeader.PdsExcludeFromRebate = NoYes::No;
    }
    salesAgreementHeader.PricingMonth = pricingMonth;
    salesAgreementHeader.DefaultExpirationDate = defaultAgreementLineExpirationDate;
    salesAgreementHeader.PricingFromDate = pricingFromDate;
    salesAgreementHeader.PricingTodate = pricingToDate;
    salesAgreementHeader.AdvanceDue = advanceDue;
    salesAgreementHeader.FromDatePort = fromDatePort;
    salesAgreementHeader.ToDatePort = toDatePort;
    salesAgreementHeader.ImportDate = importDate;
    salesAgreementHeader.BLDATE = bLDATE;
    salesAgreementHeader.FixedExchangeRate = fixedExchangeRate;
    salesAgreementHeader.ReportingCurrencyFixedExchangeRate = reportingCurrencyFixedExchangeRate;
    salesAgreementHeader.DefaultLedgerDimensionDisplayValue = defaultDimStr;
    salesAgreementHeader.Through = through;
    if(through && CommissionValue)
    {
        if(CommissionType == "Quantity")
        {
            salesAgreementHeader.BrokerageCommissionType     = ETGBrokerageCommissionType::Quantity;
        }
        else
        {
            salesAgreementHeader.BrokerageCommissionType     = ETGBrokerageCommissionType::Percent;
        }
        salesAgreementHeader.BrokerageCommissionValue = str2Num(CommissionValue);
    }

     salesAgreementHeader.DefaultLedgerDimensionDisplayValue     = Vertical + "|"
                                                                + BusinessUnit + "|"
                                                                + MainCommodity + "|"
                                                                + SubCommodity + "|"
                                                                + Contract + "|"
                                                                + TraderEmployee + "|"
                                                                + Intercompany + "|"
                                                                + costcenter + "|"
                                                                + Line_of_Business + "|"
                                                                + Plant_Warehouse_Office + "|"
                                                                + Items;

    salesAgreementHeader.NOOFCONTAINERS = numberOfContainer;
    salesAgreementHeader.NETWEIGHTMTS = netWightMTS;
    salesAgreementHeader.GROSSWEIGHTMTS = grossWeightMTS;
    salesAgreementHeader.SellingLegalEntityId = curExt();
    if(salesAgreementHeader.validateWrite())
    {
        salesAgreementHeader.insert();
        info(strFmt("Agreement id %1 is successfully created", salesAgreementHeader.SalesAgreementId));
    }
    else
    {
        warning(strFmt("Failed. Agreement id %1 is not created", salesAgreementHeader.SalesAgreementId));
    }
}
